DELETE FROM user_membership_roles
WHERE id = '00000000-0000-0000-0000-000000000602';

INSERT INTO user_membership_roles (id, membership_id, role_id, status)
SELECT '00000000-0000-0000-0000-000000000604', '00000000-0000-0000-0000-000000000502', '00000000-0000-0000-0000-000000000211', 'active'
WHERE NOT EXISTS (
    SELECT 1 FROM user_membership_roles
    WHERE membership_id = '00000000-0000-0000-0000-000000000502'
      AND role_id = '00000000-0000-0000-0000-000000000211'
      AND status = 'active'
);

